const path = require('path');

// Load problems data from JSON
const problemsDataPath = path.resolve(__dirname, '../../data/problems.json');
let problems = [];
try {
  const rawData = fs.readFileSync(problemsDataPath, 'utf8');
  problems = JSON.parse(rawData);
} catch (e) {
  problems = [];
}

/**
 * Get problem listing with filtering, paging, sorting, and metadata
 * @param {Object} options
 * @param {string} [options.difficulty] - difficulty filter, e.g. 'Easy', 'Medium', 'Hard'
 * @param {boolean} [options.includeComponents] - whether to include sorted componentLanguages
 * @param {number} [options.limit=50] - max number of results to return
 * @returns {Object} result with problems array and metadata
 */
async function listProblems({ difficulty, includeComponents = false, limit = 50 } = {}) {
  // Validate limit
  if (typeof limit !== 'number' || limit <= 0) {
    limit = 50;
  }

  // Filter by difficulty if provided
  let filtered = problems;
  if (difficulty) {
    filtered = filtered.filter(p => p.difficulty === difficulty);
  }

  // Sort by roundId ascending (deterministic ordering)
  filtered.sort((a, b) => {
    if (a.roundId < b.roundId) return -1;
    if (a.roundId > b.roundId) return 1;
    return 0;
  });

  // Apply paging limit
  const limited = filtered.slice(0, limit);

  // Compose difficulty breakdown
  const difficultyBreakdown = {};
  for (const p of problems) {
    difficultyBreakdown[p.difficulty] = (difficultyBreakdown[p.difficulty] || 0) + 1;
  }

  // If includeComponents, add sorted componentLanguages to each problem
  const problemsWithComponents = limited.map(p => {
    if (includeComponents && Array.isArray(p.componentLanguages)) {
      return {
        ...p,
        componentLanguages: [...p.componentLanguages].sort(),
      };
    }
    return p;
  });

  return {
    problems: problemsWithComponents,
    totalProblems: problems.length,
    filteredCount: filtered.length,
    appliedLimit: limited.length,
    difficultyBreakdown
  };
}

module.exports = {
  listProblems
};
